Code:
public int[] shiftLeft(int[] nums)
{
    if(nums.length <= 1)
        return nums;

    int first = nums[0];
    for(int i = 1; i < nums.length; i++)
    {
        nums[i - 1] = nums[i];
    }
    nums[nums.length - 1] = first;

    return nums;
}

public boolean evenlySpaced(int a, int b, int c) {
    int[] values = {a, b, c};
    Arrays.sort(values);

    int small = values[0];
    int middle = values[1];
    int large = values[2];

    int diff1 = middle - small;
    int diff2 = large - middle;

    return diff1 == diff2;
}
